using M1PasswordConnect.Standard;
using Microsoft.Extensions.Configuration;
using Environment = M1PasswordConnect.Standard.Environment;

namespace ConsoleApp;

// Build the IConfiguration using .NET conventions (JSON, environment, etc.)
var configuration = new ConfigurationBuilder()
    .AddJsonFile("config.json")
    .AddEnvironmentVariables() // [optional] read environment variables
    .Build();

// Instantiate your SDK builder and configure it from IConfiguration with overrides
var client = M1PasswordConnectClient.Builder
    .FromConfiguration(configuration.GetSection("M1PasswordConnect"))
    .Environment(Environment.Production)
    .HttpClientConfig(c => c.Timeout(TimeSpan.FromSeconds(60)))
    .Build();

{
  "M1PasswordConnect": {
    "Environment": "production",
    "BearerAuthCredentials": {
      "AccessToken": "accessToken",
    },
    "LoggingConfig": {
      "LogLevel": "Debug",
      "MaskSensitiveHeaders": true,
      "RequestLoggingConfiguration": {
        "Body": true,
        "Headers": true,
        "IncludeQueryInPath": true,
        "HeadersToInclude": [
          "Content-Type",
          "X-Request-ID"
        ],
        "HeadersToExclude": [
          "Authorization"
        ],
        "HeadersToUnmask": [
          "X-Request-ID"
        ],
      },
      "ResponseLoggingConfiguration": {
        "Body": true,
        "Headers": true,
        "IncludeQueryInPath": true,
        "HeadersToInclude": [
          "Content-Type",
          "X-Correlation-ID",
          "Date",
          "Server"
        ],
        "HeadersToExclude": [
          "Set-Cookie",
          "Authorization",
          "X-API-Key"
        ],
        "HeadersToUnmask": [
          "X-Correlation-ID"
        ],
      }
    },
    "HttpClientConfig": {
      "Timeout": "00:01:00",
      "NumberOfRetries": 3,
      "BackoffFactor": 2,
      "RetryInterval": 1,
      "MaximumRetryWaitTime": "00:02:00",
      "StatusCodesToRetry": [408, 413],
      "RequestMethodsToRetry": ["GET", "PUT", "DELETE"],
      "ProxyConfiguration": {
        "Address": "http://localhost:3000",
        "Port": 8080,
        "Tunnel": false,
        "User": "username",
        "Pass": "password",
      }
    }
  }
}

using Microsoft.Extensions.Logging;
using M1PasswordConnect.Standard;

namespace ConsoleApp;

var factory = LoggerFactory.Create(builder => { builder.AddConsole(); });
var logger = factory.CreateLogger<M1PasswordConnectClient>();

var client = new M1PasswordConnectClient.Builder()
    .LoggingConfig(config => config
        .Logger(logger)
        .LogLevel(LogLevel.Information)
        .RequestConfig(reqConfig => reqConfig.Body(true))
        .ResponseConfig(respConfig => respConfig.Headers(true))
    )
    .Build();

