using M1PasswordConnect.Standard.Http.Client.Proxy;

namespace ConsoleApp;

var client = new M1PasswordConnectClient.Builder()
.HttpClientConfig(config => config
    .Proxy(new ProxyConfigurationBuilder("http://localhost")
            .Port(8080)
            .Tunnel(false)
            .Auth("user", "pass")
    )
)
.Build();

